VALUES
('ph-web-foundations', NULL, 1, 'phase', NULL, NULL, NULL, 'Web Foundations and Full Stack Orientation', 'Build the mental model for how browsers, servers, networks, hosting, and frontend-backend boundaries fit together.', 'This node builds practical full stack ability in web foundations and full stack orientation.', 'trunk', 'ph-web-foundations', 1, 0, 18, 'beginner', 100, NULL, NULL, '{"source": "platform-generated", "visualRole": "trunk", "careerRole": "Full Stack Developer"}'::jsonb, true, false, '["Explain the purpose and tradeoffs of Web Foundations and Full Stack Orientation.", "Apply Web Foundations and Full Stack Orientation in a realistic full stack application context."]'::jsonb, '["Produce notes, code, tests, diagrams, or examples that demonstrate Web Foundations and Full Stack Orientation.", "Be able to explain the implementation decisions and common failure modes."]'::jsonb),
('grp-web-model', 'ph-web-foundations', 1, 'choice_group', NULL, 'complete_all', 4, 'Web Platform Mental Model', 'Organizes the web platform mental model work inside Web Foundations and Full Stack Orientation.', 'This node builds practical full stack ability in web platform mental model.', 'side', 'ph-web-foundations', 1, 1, 7, 'beginner', 90, NULL, NULL, '{"source": "platform-generated", "selectionType": "complete_all", "careerRole": "Full Stack Developer"}'::jsonb, true, false, '["Explain the purpose and tradeoffs of Web Platform Mental Model.", "Apply Web Platform Mental Model in a realistic full stack application context."]'::jsonb, '["Produce notes, code, tests, diagrams, or examples that demonstrate Web Platform Mental Model.", "Be able to explain the implementation decisions and common failure modes."]'::jsonb),
('internet-dns-and-hosting', 'grp-web-model', 1, 'topic', NULL, NULL, NULL, 'Internet, DNS, and Hosting Basics', 'Explain how users reach web apps through DNS, hosting, HTTPS, and client/server communication.', 'This node builds practical full stack ability in internet, dns, and hosting basics.', 'choice', 'grp-web-model', 1, 1, 3, 'beginner', 80, NULL, NULL, '{"source": "platform-generated", "careerRole": "Full Stack Developer"}'::jsonb, true, true, '["Explain the purpose and tradeoffs of Internet, DNS, and Hosting Basics.", "Apply Internet, DNS, and Hosting Basics in a realistic full stack application context."]'::jsonb, '["Produce notes, code, tests, diagrams, or examples that demonstrate Internet, DNS, and Hosting Basics.", "Be able to explain the implementation decisions and common failure modes."]'::jsonb),
('http-request-response-lifecycle', 'grp-web-model', 2, 'topic', NULL, NULL, NULL, 'HTTP Request and Response Lifecycle', 'Trace requests through browser, network, server, response parsing, and caching behavior.', 'This node builds practical full stack ability in http request and response lifecycle.', 'choice', 'grp-web-model', 1, 2, 4, 'beginner', 80, NULL, NULL, '{"source": "platform-generated", "careerRole": "Full Stack Developer"}'::jsonb, true, true, '["Explain the purpose and tradeoffs of HTTP Request and Response Lifecycle.", "Apply HTTP Request and Response Lifecycle in a realistic full stack application context."]'::jsonb, '["Produce notes, code, tests, diagrams, or examples that demonstrate HTTP Request and Response Lifecycle.", "Be able to explain the implementation decisions and common failure modes."]'::jsonb),
('browser-rendering-model', 'grp-web-model', 3, 'topic', NULL, NULL, NULL, 'Browser Rendering Model', 'Understand how browsers parse HTML/CSS/JS, build render trees, and update the screen.', 'This node builds practical full stack ability in browser rendering model.', 'choice', 'grp-web-model', 1, 3, 4, 'beginner', 80, NULL, NULL, '{"source": "platform-generated", "careerRole": "Full Stack Developer"}'::jsonb, true, true, '["Explain the purpose and tradeoffs of Browser Rendering Model.", "Apply Browser Rendering Model in a realistic full stack application context."]'::jsonb, '["Produce notes, code, tests, diagrams, or examples that demonstrate Browser Rendering Model.", "Be able to explain the implementation decisions and common failure modes."]'::jsonb),
('frontend-backend-boundaries', 'grp-web-model', 4, 'topic', NULL, NULL, NULL, 'Frontend and Backend Responsibilities', 'Distinguish UI concerns, server concerns, persistence, API contracts, and deployment boundaries.', 'This node builds practical full stack ability in frontend and backend responsibilities.', 'choice', 'grp-web-model', 1, 4, 3, 'beginner', 80, NULL, NULL, '{"source": "platform-generated", "careerRole": "Full Stack Developer"}'::jsonb, true, true, '["Explain the purpose and tradeoffs of Frontend and Backend Responsibilities.", "Apply Frontend and Backend Responsibilities in a realistic full stack application context."]'::jsonb, '["Produce notes, code, tests, diagrams, or examples that demonstrate Frontend and Backend Responsibilities.", "Be able to explain the implementation decisions and common failure modes."]'::jsonb),
('grp-tooling-basics', 'ph-web-foundations', 2, 'choice_group', NULL, 'complete_all', 4, 'Developer Tooling Basics', 'Organizes the developer tooling basics work inside Web Foundations and Full Stack Orientation.', 'This node builds practical full stack ability in developer tooling basics.', 'side', 'ph-web-foundations', 1, 2, 7, 'beginner', 90, NULL, NULL, '{"source": "platform-generated", "selectionType": "complete_all", "careerRole": "Full Stack Developer"}'::jsonb, true, false, '["Explain the purpose and tradeoffs of Developer Tooling Basics.", "Apply Developer Tooling Basics in a realistic full stack application context."]'::jsonb, '["Produce notes, code, tests, diagrams, or examples that demonstrate Developer Tooling Basics.", "Be able to explain the implementation decisions and common failure modes."]'::jsonb),
('git-github-workflow', 'grp-tooling-basics', 1, 'topic', NULL, NULL, NULL, 'Git and GitHub Workflow', 'Use commits, branches, pull requests, reviews, and repository hygiene in a team workflow.', 'This node builds practical full stack ability in git and github workflow.', 'choice', 'grp-tooling-basics', 1, 1, 4, 'beginner', 80, NULL, NULL, '{"source": "platform-generated", "careerRole": "Full Stack Developer"}'::jsonb, true, true, '["Explain the purpose and tradeoffs of Git and GitHub Workflow.", "Apply Git and GitHub Workflow in a realistic full stack application context."]'::jsonb, '["Produce notes, code, tests, diagrams, or examples that demonstrate Git and GitHub Workflow.", "Be able to explain the implementation decisions and common failure modes."]'::jsonb),
('package-managers-and-scripts', 'grp-tooling-basics', 2, 'topic', NULL, NULL, NULL, 'Package Managers and Project Scripts', 'Use npm scripts, package metadata, dependency versions, and lockfiles safely.', 'This node builds practical full stack ability in package managers and project scripts.', 'choice', 'grp-tooling-basics', 1, 2, 3, 'beginner', 80, NULL, NULL, '{"source": "platform-generated", "careerRole": "Full Stack Developer"}'::jsonb, true, true, '["Explain the purpose and tradeoffs of Package Managers and Project Scripts.", "Apply Package Managers and Project Scripts in a realistic full stack application context."]'::jsonb, '["Produce notes, code, tests, diagrams, or examples that demonstrate Package Managers and Project Scripts.", "Be able to explain the implementation decisions and common failure modes."]'::jsonb),
('browser-devtools-debugging', 'grp-tooling-basics', 3, 'topic', NULL, NULL, NULL, 'Browser DevTools Debugging', 'Inspect DOM, CSS, network requests, storage, console output, and performance signals.', 'This node builds practical full stack ability in browser devtools debugging.', 'choice', 'grp-tooling-basics', 1, 3, 4, 'beginner', 80, NULL, NULL, '{"source": "platform-generated", "careerRole": "Full Stack Developer"}'::jsonb, true, true, '["Explain the purpose and tradeoffs of Browser DevTools Debugging.", "Apply Browser DevTools Debugging in a realistic full stack application context."]'::jsonb, '["Produce notes, code, tests, diagrams, or examples that demonstrate Browser DevTools Debugging.", "Be able to explain the implementation decisions and common failure modes."]'::jsonb),
('full-stack-project-structure', 'grp-tooling-basics', 4, 'topic', NULL, NULL, NULL, 'Full Stack Project Structure', 'Organize client, server, shared code, config, docs, and environment files clearly.', 'This node builds practical full stack ability in full stack project structure.', 'choice', 'grp-tooling-basics', 1, 4, 4, 'beginner', 80, NULL, NULL, '{"source": "platform-generated", "careerRole": "Full Stack Developer"}'::jsonb, true, true, '["Explain the purpose and tradeoffs of Full Stack Project Structure.", "Apply Full Stack Project Structure in a realistic full stack application context."]'::jsonb, '["Produce notes, code, tests, diagrams, or examples that demonstrate Full Stack Project Structure.", "Be able to explain the implementation decisions and common failure modes."]'::jsonb),
('chk-web-foundations', 'ph-web-foundations', 90, 'checkpoint', 'review', NULL, NULL, 'Web Foundations and Full Stack Orientation Review Checkpoint', 'Validate evidence from Web Foundations and Full Stack Orientation: notes, working examples, code, tests, diagrams, or deployed artifacts where applicable.', 'This node builds practical full stack ability in web foundations and full stack orientation review checkpoint.', 'checkpoint', 'ph-web-foundations', 1, 90, 2, 'beginner', 95, NULL, NULL, '{"source": "platform-generated", "checkpointType": "review"}'::jsonb, true, true, '["Review evidence from Web Foundations and Full Stack Orientation.", "Identify gaps before moving to the next phase."]'::jsonb, '["Checklist or review notes confirm the core phase outcomes.", "Any missing prerequisites are identified before continuing."]'::jsonb),
('proj-dev-environment', 'ph-web-foundations', 101, 'project', NULL, NULL, NULL, 'Optional Full Stack Development Environment Setup', 'Set up a repo with client/server folders, npm scripts, linting, formatting, environment examples, and a README.', 'This node builds practical full stack ability in optional full stack development environment setup.', 'side', 'ph-web-foundations', 1, 101, 4, 'beginner', 60, NULL, NULL, '{"source": "platform-generated", "projectType": "mini_project", "careerRole": "Full Stack Developer"}'::jsonb, false, true, '["Build a working deliverable for Optional Full Stack Development Environment Setup.", "Document implementation decisions, setup steps, tradeoffs, and evidence of completion."]'::jsonb, '["Working project or feature is committed to a repository.", "README documents setup, behavior, screenshots or demo notes, and known limitations.", "Relevant tests, validation, or manual verification notes are included."]'::jsonb),
('ph-html-css-ux', NULL, 2, 'phase', NULL, NULL, NULL, 'HTML, CSS, Accessibility, and Responsive UI', 'Develop the frontend foundation needed to build usable, accessible, responsive interfaces before adding application complexity.', 'This node builds practical full stack ability in html, css, accessibility, and responsive ui.', 'trunk', 'ph-html-css-ux', 2, 0, 18, 'beginner', 100, NULL, NULL, '{"source": "platform-generated", "visualRole": "trunk", "careerRole": "Full Stack Developer"}'::jsonb, true, false, '["Explain the purpose and tradeoffs of HTML, CSS, Accessibility, and Responsive UI.", "Apply HTML, CSS, Accessibility, and Responsive UI in a realistic full stack application context."]'::jsonb, '["Produce notes, code, tests, diagrams, or examples that demonstrate HTML, CSS, Accessibility, and Responsive UI.", "Be able to explain the implementation decisions and common failure modes."]'::jsonb),
('grp-html-accessibility', 'ph-html-css-ux', 1, 'choice_group', NULL, 'complete_all', 4, 'Semantic HTML and Accessibility', 'Organizes the semantic html and accessibility work inside HTML, CSS, Accessibility, and Responsive UI.', 'This node builds practical full stack ability in semantic html and accessibility.', 'side', 'ph-html-css-ux', 2, 1, 8, 'beginner', 90, NULL, NULL, '{"source": "platform-generated", "selectionType": "complete_all", "careerRole": "Full Stack Developer"}'::jsonb, true, false, '["Explain the purpose and tradeoffs of Semantic HTML and Accessibility.", "Apply Semantic HTML and Accessibility in a realistic full stack application context."]'::jsonb, '["Produce notes, code, tests, diagrams, or examples that demonstrate Semantic HTML and Accessibility.", "Be able to explain the implementation decisions and common failure modes."]'::jsonb),
