-- ============================================================
-- fullstack-developer-roadmap.seed.sql
-- Full Stack Developer roadmap seed.
-- Frontend-first curated full stack path with backend, database, auth, testing,
-- deployment, performance, and capstone coverage.
-- Re-runnable/idempotent for this roadmap title.
-- ============================================================

BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

DROP TABLE IF EXISTS seed_edge;
DROP TABLE IF EXISTS seed_node_resource;
DROP TABLE IF EXISTS seed_node_skill;
DROP TABLE IF EXISTS seed_node;
DROP TABLE IF EXISTS seed_resource;
DROP TABLE IF EXISTS seed_skill;
DROP TABLE IF EXISTS seed_roadmap_map;

-- Clean previous copy of this specific roadmap only.
DELETE FROM public.progress_event
WHERE roadmap_enrollment_id IN (
    SELECT e.roadmap_enrollment_id
    FROM public.roadmap_enrollment e
    JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title IN ('Full Stack Developer Roadmap', 'Fullstack Developer Roadmap', 'Full Stack Developer Roadmap - Full Detailed Seed')
);

DELETE FROM public.user_node_progress
WHERE roadmap_enrollment_id IN (
    SELECT e.roadmap_enrollment_id
    FROM public.roadmap_enrollment e
    JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title IN ('Full Stack Developer Roadmap', 'Fullstack Developer Roadmap', 'Full Stack Developer Roadmap - Full Detailed Seed')
);

DELETE FROM public.roadmap_enrollment
WHERE roadmap_version_id IN (
    SELECT rv.roadmap_version_id
    FROM public.roadmap_version rv
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title IN ('Full Stack Developer Roadmap', 'Fullstack Developer Roadmap', 'Full Stack Developer Roadmap - Full Detailed Seed')
);

DELETE FROM public.roadmap
WHERE title IN ('Full Stack Developer Roadmap', 'Fullstack Developer Roadmap', 'Full Stack Developer Roadmap - Full Detailed Seed');

VALUES (
    'Full Stack Developer',
    'full-stack-developer',
    'Frontend-first full stack development path covering client-side engineering, APIs, databases, authentication, testing, deployment, performance, and production-ready project work.',
    'Software Engineering',
    true
)
ON CONFLICT (slug) DO UPDATE SET
    name = EXCLUDED.name,
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    is_active = true,
    updated_at = now();

DROP TABLE IF EXISTS seed_roadmap_map;
CREATE TEMP TABLE seed_roadmap_map AS
WITH role_row AS (
    SELECT career_role_id FROM public.career_role WHERE slug = 'full-stack-developer'
), inserted_roadmap AS (
    SELECT
        career_role_id,
        'Full Stack Developer Roadmap',
        'A structured learning path for becoming a full stack developer with a frontend-first focus, covering web fundamentals, HTML, CSS, JavaScript, TypeScript, React, frontend architecture, backend APIs, databases, authentication, testing, deployment, performance, DevOps awareness, and portfolio-ready full stack applications.',
        'template',
        'static',
        'public'
    FROM role_row
    RETURNING roadmap_id
), inserted_version AS (
    SELECT
        roadmap_id,
        1,
        'published',
        'Full Stack Developer Roadmap v1',
        'A practical frontend-first full stack roadmap that moves from web fundamentals to production-ready applications through guided topics, checkpoints, optional practice projects, and required milestone projects.',
        410,
        'none',
        '{"source":"platform-generated","referenceSeeds":["frontend-developer","backend-developer"],"focus":"frontend-first full stack","estimatedHoursPolicy":"representative required path"}'::jsonb,
        'TB',
        'custom',
        now()
    FROM inserted_roadmap
    RETURNING roadmap_version_id, roadmap_id
)
SELECT roadmap_id, roadmap_version_id FROM inserted_version;

-- Skills.
DROP TABLE IF EXISTS seed_skill;
CREATE TEMP TABLE seed_skill (
    slug text PRIMARY KEY,
    name text NOT NULL,
    category text NOT NULL,
    description text NOT NULL
) ON COMMIT DROP;


UPDATE public.skill s
SET
    name = ss.name,
    category = ss.category,
    description = ss.description,
    is_active = true
FROM seed_skill ss
WHERE s.slug = ss.slug;

SELECT ss.name, ss.slug, ss.category, ss.description, true
FROM seed_skill ss
WHERE NOT EXISTS (
    SELECT 1 FROM public.skill s WHERE s.slug = ss.slug OR s.name = ss.name
);

-- Learning resources.
DROP TABLE IF EXISTS seed_resource;
CREATE TEMP TABLE seed_resource (
    resource_key text PRIMARY KEY,
    title text NOT NULL,
    url text NOT NULL,
    resource_type text NOT NULL,
    description text NOT NULL,
    provider text,
    difficulty_level text
) ON COMMIT DROP;


UPDATE public.learning_resource lr
SET
    title = sr.title,
    resource_type = sr.resource_type,
    description = sr.description,
    provider = sr.provider,
    difficulty_level = sr.difficulty_level,
    language_code = 'en',
    verification_status = 'verified',
    updated_at = now()
FROM (
    SELECT DISTINCT ON (url)
        title,
        url,
        resource_type,
        description,
        provider,
        difficulty_level
    FROM seed_resource
    ORDER BY url, resource_key
) sr
WHERE lr.url = sr.url;

SELECT
    sr.title,
    sr.url,
    sr.resource_type,
    sr.description,
    sr.provider,
    sr.difficulty_level,
    'en',
    'verified'
FROM (
    SELECT DISTINCT ON (url)
        title,
        url,
        resource_type,
        description,
        provider,
        difficulty_level
    FROM seed_resource
    ORDER BY url, resource_key
) sr
WHERE NOT EXISTS (
    SELECT 1 FROM public.learning_resource lr WHERE lr.url = sr.url
);

-- Roadmap nodes.
DROP TABLE IF EXISTS seed_node;
CREATE TEMP TABLE seed_node (
    node_id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    node_key text UNIQUE NOT NULL,
    parent_key text,
    order_index int NOT NULL,
    node_type text NOT NULL,
    checkpoint_type text,
    selection_type text,
    required_count int,
    title text NOT NULL,
    description text,
    reason text,
    layout_role text NOT NULL,
    layout_group text,
    layout_rank int,
    layout_order int NOT NULL,
    estimated_hours int,
    difficulty_level text,
    priority int NOT NULL,
    position_x numeric(10,2),
    position_y numeric(10,2),
    metadata jsonb NOT NULL,
    is_required boolean NOT NULL,
    is_trackable boolean NOT NULL,
    learning_outcomes jsonb NOT NULL,
    completion_criteria jsonb NOT NULL
) ON COMMIT DROP;


SELECT
    sn.node_id,
    m.roadmap_version_id,
    parent.node_id,
    sn.node_key,
    sn.node_type,
    sn.checkpoint_type,
    sn.selection_type,
    sn.required_count,
    sn.title,
    sn.description,
    sn.reason,
    sn.order_index,
    sn.layout_role,
    sn.layout_group,
    sn.layout_rank,
    sn.layout_order,
    sn.estimated_hours,
    sn.difficulty_level,
    sn.priority,
    sn.position_x,
    sn.position_y,
    sn.metadata,
    sn.is_required,
    sn.is_trackable,
    sn.learning_outcomes,
    sn.completion_criteria
FROM seed_node sn
CROSS JOIN seed_roadmap_map m
LEFT JOIN seed_node parent ON parent.node_key = sn.parent_key
ON CONFLICT (roadmap_version_id, slug) DO UPDATE SET
    parent_node_id = EXCLUDED.parent_node_id,
    node_type = EXCLUDED.node_type,
    checkpoint_type = EXCLUDED.checkpoint_type,
    selection_type = EXCLUDED.selection_type,
    required_count = EXCLUDED.required_count,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    reason = EXCLUDED.reason,
    order_index = EXCLUDED.order_index,
    layout_role = EXCLUDED.layout_role,
    layout_group = EXCLUDED.layout_group,
    layout_rank = EXCLUDED.layout_rank,
    layout_order = EXCLUDED.layout_order,
    estimated_hours = EXCLUDED.estimated_hours,
    difficulty_level = EXCLUDED.difficulty_level,
    priority = EXCLUDED.priority,
    position_x = EXCLUDED.position_x,
    position_y = EXCLUDED.position_y,
    metadata = EXCLUDED.metadata,
    is_required = EXCLUDED.is_required,
    is_trackable = EXCLUDED.is_trackable,
    learning_outcomes = EXCLUDED.learning_outcomes,
    completion_criteria = EXCLUDED.completion_criteria;

-- Node-skill mappings.
DROP TABLE IF EXISTS seed_node_skill;
CREATE TEMP TABLE seed_node_skill (
    node_key text NOT NULL,
    skill_slug text NOT NULL
) ON COMMIT DROP;


SELECT DISTINCT
    rn.roadmap_node_id,
    resolved_skill.skill_id
FROM seed_node_skill sns
JOIN seed_node sn ON sn.node_key = sns.node_key
JOIN seed_roadmap_map m ON true
JOIN public.roadmap_node rn
    ON rn.roadmap_version_id = m.roadmap_version_id
   AND rn.slug = sn.node_key
LEFT JOIN seed_skill ss ON ss.slug = sns.skill_slug
JOIN LATERAL (
    SELECT s.skill_id
    FROM public.skill s
    WHERE s.slug = sns.skill_slug
       OR (ss.name IS NOT NULL AND s.name = ss.name)
    ORDER BY CASE WHEN s.slug = sns.skill_slug THEN 0 ELSE 1 END
    LIMIT 1
) resolved_skill ON true
ON CONFLICT (roadmap_node_id, skill_id) DO NOTHING;

-- Node-resource mappings.
DROP TABLE IF EXISTS seed_node_resource;
CREATE TEMP TABLE seed_node_resource (
    node_key text NOT NULL,
    resource_key text NOT NULL,
    order_index int NOT NULL
) ON COMMIT DROP;


WITH resolved AS (
    SELECT
        rn.roadmap_node_id,
        lr.learning_resource_id,
        snr.order_index,
        snr.order_index <= 3 AS is_primary,
        ROW_NUMBER() OVER (
            PARTITION BY rn.roadmap_node_id, lr.learning_resource_id
            ORDER BY snr.order_index
        ) AS row_no
    FROM seed_node_resource snr
    JOIN seed_node sn ON sn.node_key = snr.node_key
    JOIN seed_roadmap_map m ON true
    JOIN public.roadmap_node rn
        ON rn.roadmap_version_id = m.roadmap_version_id
       AND rn.slug = sn.node_key
    JOIN seed_resource sr ON sr.resource_key = snr.resource_key
    JOIN public.learning_resource lr ON lr.url = sr.url
)
SELECT
    roadmap_node_id,
    learning_resource_id,
    order_index,
    is_primary
FROM resolved
WHERE row_no = 1
ON CONFLICT (roadmap_node_id, learning_resource_id) DO UPDATE SET
    order_index = EXCLUDED.order_index,
    is_primary = EXCLUDED.is_primary;

SELECT DISTINCT
    lr.learning_resource_id,
    resolved_skill.skill_id
FROM seed_node_resource snr
JOIN seed_node_skill sns ON sns.node_key = snr.node_key
JOIN seed_resource sr ON sr.resource_key = snr.resource_key
JOIN public.learning_resource lr ON lr.url = sr.url
LEFT JOIN seed_skill ss ON ss.slug = sns.skill_slug
JOIN LATERAL (
    SELECT s.skill_id
    FROM public.skill s
    WHERE s.slug = sns.skill_slug
       OR (ss.name IS NOT NULL AND s.name = ss.name)
    ORDER BY CASE WHEN s.slug = sns.skill_slug THEN 0 ELSE 1 END
    LIMIT 1
) resolved_skill ON true
ON CONFLICT (learning_resource_id, skill_id) DO NOTHING;

-- Edges.
DROP TABLE IF EXISTS seed_edge;
CREATE TEMP TABLE seed_edge (
    from_key text NOT NULL,
    to_key text NOT NULL,
    edge_type text NOT NULL,
    dependency_type text NOT NULL,
    condition jsonb NOT NULL
) ON COMMIT DROP;


SELECT
    m.roadmap_version_id,
    source.node_id,
    target.node_id,
    se.edge_type,
    se.dependency_type,
    se.condition
FROM seed_edge se
CROSS JOIN seed_roadmap_map m
JOIN seed_node source ON source.node_key = se.from_key
JOIN seed_node target ON target.node_key = se.to_key
ON CONFLICT (roadmap_version_id, from_node_id, to_node_id, edge_type) DO UPDATE SET
    dependency_type = EXCLUDED.dependency_type,
    condition = EXCLUDED.condition;

COMMIT;

-- Summary:
-- Skills: 201
-- Learning resources: 91
-- Roadmap nodes: 193
-- Node-skill mappings: 428
-- Node-resource mappings: 602
-- Edges: 296
